mapper.select:
SELECT p.PLANT_CD AS plantCd, p.COMPANY_CD AS companyCd, c.COMPANY_NM AS companyNm, p.PLANT_NM AS plantNm, p.ADDR AS addr, p.TEL_NO AS telNo, p.USE_YN AS useYn FROM MST_PLANT p JOIN MST_COMPANY c ON c.COMPANY_CD = p.COMPANY_CD WHERE 1 = 1
AND p.COMPANY_CD = #{companyCd}
AND p.PLANT_NM LIKE CONCAT('%', #{plantNm}, '%')
AND p.USE_YN = #{useYn}
ORDER BY p.PLANT_CD

mapper.insert:
